import PriceData from "../src/data/price.js";

const app = document.getElementById('app');

// Функция для отображения формы редактирования цен
function renderPriceEditor() {
    const keys = Object.keys(PriceData.employee);
    keys.forEach(key => {
        const section = PriceData.employee[key];
        const heading = document.createElement('h2');
        heading.textContent = key;
        app.appendChild(heading);
        Object.keys(section).forEach(subKey => {
            const subSection = section[subKey];
            const subHeading = document.createElement('h3');
            subHeading.textContent = subKey;
            app.appendChild(subHeading);
            subSection.forEach(item => {
                const label = document.createElement('label');
                label.textContent = `${item.key}: `;
                const input = document.createElement('input');
                input.type = 'number';
                input.value = item.price;
                input.addEventListener('change', () => {
                    item.price = parseInt(input.value);
                });
                app.appendChild(label);
                app.appendChild(input);
                app.appendChild(document.createElement('br'));
            });
            app.appendChild(document.createElement('hr'));
        });
    });

    // Создание кнопки "Сохранить"
    const saveButton = document.createElement('button');
    saveButton.textContent = 'Сохранить';
    saveButton.addEventListener('click', () => {
        savePrices();
    });
    app.appendChild(saveButton);
}

// Функция для сохранения изменений
function savePrices() {
    console.log('Отправка данных на сервер:', PriceData);

    fetch('http://localhost:3000/save-prices', {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json'
        },
        body: JSON.stringify(PriceData)
    })
    .then(response => {
        console.log('Ответ сервера:', response);
        if (!response.ok) {
            return response.text().then(text => { throw new Error(text) });
        }
        return response.text();
    })
    .then(data => {
        console.log('Данные успешно сохранены:', data);
        alert('Изменения сохранены');
    })
    .catch(error => {
        console.error('Ошибка при сохранении данных:', error);
        alert(`Ошибка при сохранении данных: ${error.message}`);
    });
}

renderPriceEditor();